import{_ as t,o as a,c as r,a0 as o}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Restore a Deleted Import","description":"","frontmatter":{},"headers":[],"relativePath":"imports/restore-import.md","filePath":"imports/restore-import.md"}'),s={name:"imports/restore-import.md"};function i(l,e,n,p,h,d){return a(),r("div",null,[...e[0]||(e[0]=[o(`<h1 id="restore-a-deleted-import" tabindex="-1">Restore a Deleted Import <a class="header-anchor" href="#restore-a-deleted-import" aria-label="Permalink to &quot;Restore a Deleted Import&quot;">​</a></h1><p>Restoring an import brings the import back for review. It does not instantly re-save all of its old live results.</p><blockquote><p>Screenshot placeholder: bin-restore-import.png Screenshot placeholder: import-restored-draft.png</p></blockquote><h2 id="the-restore-path" tabindex="-1">The restore path <a class="header-anchor" href="#the-restore-path" aria-label="Permalink to &quot;The restore path&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;Accepted import&quot;] --&gt; B[&quot;Delete import &amp; rollback&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;rolled_back&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;Recycle Bin&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;Restore&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[&quot;restored_draft&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[&quot;Review rows again&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[&quot;Accept again if still correct&quot;]</span></span></code></pre></div><h2 id="what-restore-does-today" tabindex="-1">What restore does today <a class="header-anchor" href="#what-restore-does-today" aria-label="Permalink to &quot;What restore does today&quot;">​</a></h2><p>When you restore a rolled-back import:</p><ul><li>the import comes back as <code>restored_draft</code></li><li>its staging rows return</li><li>rows with a matched player are usually put back into a ready-to-apply state</li><li>rows without a matched player go back to a needs-review state</li></ul><h2 id="what-restore-does-not-do" tabindex="-1">What restore does not do <a class="header-anchor" href="#what-restore-does-not-do" aria-label="Permalink to &quot;What restore does not do&quot;">​</a></h2><p>Restore does <strong>not</strong> directly revive the previously deleted live results.</p><p>Instead, it revives the import as a reviewable draft so you can:</p><ul><li>inspect it again</li><li>fix it if needed</li><li>re-accept only the rows that should be written back</li></ul><h2 id="when-to-restore" tabindex="-1">When to restore <a class="header-anchor" href="#when-to-restore" aria-label="Permalink to &quot;When to restore&quot;">​</a></h2><p>Restore is useful when:</p><ul><li>the rollback was correct, but you still want the import as a working draft</li><li>you want to re-review the rows with better judgment</li><li>you want to re-apply only part of what was there before</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./delete-and-rollback.html">Delete an Import &amp; Roll Back Its Changes</a></li><li><a href="./review-rows.html">Review Import Rows</a></li><li><a href="./apply-import.html">Accept Rows (Apply an Import)</a></li></ul>`,17)])])}const m=t(s,[["render",i]]);export{u as __pageData,m as default};
